import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';
import { 
  Send, X, Bot, Loader2, 
  Clock, MessageSquare, Trash2,
  User, AlertCircle
} from 'lucide-react';
import './ERPChatBot.css';

const ERPChatBot = ({ onClose }) => {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isTyping, setIsTyping] = useState(false);
  const [showWelcome, setShowWelcome] = useState(true);
  const [userInfo, setUserInfo] = useState(null);
  const [isAuthenticated, setIsAuthenticated] = useState(true);
  const messagesEndRef = useRef(null);
  const inputRef = useRef(null);

  // Check authentication and get user info on mount
  useEffect(() => {
    const checkAuth = async () => {
      try {
        const response = await axios.get('http://localhost:65000/api/auth/session', {
          withCredentials: true
        });
        
        if (response.data.role === 'student') {
          // Get user details
          const userResponse = await axios.get('http://localhost:65000/api/auth/me', {
            withCredentials: true
          });
          
          setUserInfo({
            name: `${userResponse.data.user.firstName} ${userResponse.data.user.lastName}`,
            email: userResponse.data.user.email,
            role: userResponse.data.user.role
          });
          
          setIsAuthenticated(true);
          
          // Set welcome message
          const welcomeMessage = {
            id: 1,
            text: `Hello ${userResponse.data.user.firstName}! 👋 I'm your AI Assistant.\n\nI can help you with:\n• Courses & Teachers\n• Fees & Payments\n• Attendance & Timetable\n• Grades & GPA\n• Assignments & Tasks\n• Academic Progress\n• Batch Information\n\nAsk me anything about your university ERP.`,
            sender: 'bot',
            timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
            icon: '🤖'
          };
          
          setMessages([welcomeMessage]);
        } else {
          setIsAuthenticated(false);
          setMessages([{
            id: 1,
            text: "Only students can access the AI assistant. Please log in as a student.",
            sender: 'bot',
            timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
            icon: '🤖',
            isError: true
          }]);
        }
        
      } catch (error) {
        console.error("Auth check error:", error);
        setIsAuthenticated(false);
        setMessages([{
          id: 1,
          text: "Please log in to use the AI assistant.",
          sender: 'bot',
          timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
          icon: '🤖',
          isError: true
        }]);
      }
    };
    
    checkAuth();
  }, []);

  // PURE AI: Send query to function-calling chatbot
  const handleSend = async () => {
    if (!input.trim() || isLoading || !isAuthenticated) return;

    const userMessage = {
      id: Date.now(),
      text: input,
      sender: 'user',
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      icon: '👤'
    };
    
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);
    setIsTyping(true);
    setShowWelcome(false);

    try {
      // Call pure AI chatbot endpoint - NO studentId needed!
      const response = await axios.post('http://localhost:65000/api/ai/ask', {
        question: input
      }, {
        withCredentials: true,
        headers: {
          'Content-Type': 'application/json'
        }
      });

      setIsTyping(false);

      if (response.data.success) {
        const botMessage = {
          id: Date.now() + 1,
          text: response.data.answer,
          sender: 'bot',
          timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
          icon: '🤖',
          isDataResponse: true
        };
        
        setMessages(prev => [...prev, botMessage]);
      } else {
        throw new Error(response.data.message || 'Failed to get response');
      }

    } catch (error) {
      setIsTyping(false);
      
      console.error("Chatbot error:", {
        status: error.response?.status,
        message: error.message
      });
      
      let errorMessage = "Sorry, I'm having trouble processing your question. Please try again.";
      
      if (error.response?.status === 401) {
        errorMessage = "Please log in to use the AI assistant.";
        setIsAuthenticated(false);
      } else if (error.response?.status === 403) {
        errorMessage = "Only students can access this feature.";
        setIsAuthenticated(false);
      } else if (error.response?.data?.message) {
        errorMessage = error.response.data.message;
      } else if (error.message.includes('Network Error')) {
        errorMessage = "Cannot connect to AI service. Please check your connection.";
      }
      
      const errorMsg = {
        id: Date.now() + 1,
        text: errorMessage,
        sender: 'bot',
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        icon: '🤖',
        isError: true
      };
      
      setMessages(prev => [...prev, errorMsg]);
      
    } finally {
      setIsLoading(false);
    }
  };

  // Clear chat history
  const handleClearChat = async () => {
    if (!isAuthenticated) return;
    
    try {
      await axios.post('http://localhost:65000/api/ai/clear-history', {}, {
        withCredentials: true
      });
      
      const welcomeMessage = {
        id: 1,
        text: `Chat cleared! Hello again ${userInfo?.name}! 👋\n\nWhat would you like to know about your university ERP?`,
        sender: 'bot',
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        icon: '🤖'
      };
      
      setMessages([welcomeMessage]);
      setShowWelcome(true);
      
    } catch (error) {
      console.error("Error clearing chat:", error);
    }
  };

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  // Format message text with line breaks
  const formatMessage = (text) => {
    if (!text) return '';
    
    return text.split('\n').map((line, index) => {
      const trimmedLine = line.trim();
      
      // Style different types of content
      if (trimmedLine.startsWith('•') || trimmedLine.startsWith('-')) {
        return (
          <div key={index} className="bullet-point">
            {line}
          </div>
        );
      }
      
      if (/^\d+\./.test(trimmedLine)) {
        return (
          <div key={index} className="numbered-point">
            {line}
          </div>
        );
      }
      
      if (trimmedLine.includes('**') || trimmedLine.includes('__')) {
        // Simple markdown-like formatting
        const formattedLine = line
          .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
          .replace(/__(.*?)__/g, '<em>$1</em>');
        
        return (
          <div 
            key={index} 
            dangerouslySetInnerHTML={{ __html: formattedLine }}
            className="formatted-line"
          />
        );
      }
      
      if (line.trim() === '') {
        return <div key={index} className="empty-line"><br /></div>;
      }
      
      return (
        <div key={index} className="regular-line">
          {line}
        </div>
      );
    });
  };

  // Get user display name
  const getDisplayName = () => {
    if (!userInfo) return 'Student';
    return userInfo.name.split(' ')[0]; // First name only
  };

  return (
    <div className="erp-chatbot">
      {/* Header */}
      <div className="chatbot-header">
        <div className="header-left">
          <div className="ai-badge">
            <Bot size={18} />
            <span>Pure AI Assistant</span>
            {!isAuthenticated && (
              <span className="auth-badge auth-error">
                <AlertCircle size={12} />
                Not Logged In
              </span>
            )}
          </div>
          <div className="student-info">
            {userInfo ? (
              <>
                <span className="student-name">
                  <User size={14} />
                  {getDisplayName()}
                </span>
                <span className="student-role">• Student</span>
              </>
            ) : (
              <span className="student-name loading">Loading user info...</span>
            )}
          </div>
        </div>
        <div className="header-right">
          <button 
            className="clear-btn"
            onClick={handleClearChat}
            disabled={!isAuthenticated}
            title="Clear chat history"
            aria-label="Clear chat"
          >
            <Trash2 size={16} />
          </button>
          <button 
            className="close-btn" 
            onClick={onClose} 
            aria-label="Close chat"
          >
            <X size={20} />
          </button>
        </div>
      </div>

      {/* Authentication Warning */}
      {!isAuthenticated && (
        <div className="auth-warning">
          <AlertCircle size={16} />
          <span>Please log in as a student to use the AI assistant</span>
        </div>
      )}

      {/* Messages Container */}
      <div className="messages-container">
        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`message-bubble ${msg.sender} ${msg.isError ? 'error' : ''} ${msg.isDataResponse ? 'data-response' : ''}`}
          >
            <div className="message-icon">{msg.icon}</div>
            <div className="message-content">
              <div className="message-text">
                {formatMessage(msg.text)}
              </div>
              <div className="message-time">
                <Clock size={10} />
                {msg.timestamp}
              </div>
            </div>
          </div>
        ))}
        
        {isTyping && (
          <div className="message-bubble bot typing">
            <div className="message-icon">🤖</div>
            <div className="message-content">
              <div className="typing-indicator">
                <span></span>
                <span></span>
                <span></span>
              </div>
              <div className="message-time">
                <Clock size={10} />
                Thinking...
              </div>
            </div>
          </div>
        )}
        
        <div ref={messagesEndRef} />
      </div>

      {/* Welcome Hint (only shown initially) */}
      {showWelcome && messages.length === 1 && isAuthenticated && (
        <div className="welcome-hint">
          <MessageSquare size={14} />
          <span>Ask me anything about your courses, fees, attendance, or academic progress.</span>
        </div>
      )}

      {/* Input Area */}
      <div className="input-container">
        <div className="input-wrapper">
          <input
            ref={inputRef}
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyPress={handleKeyPress}
            placeholder={
              !isAuthenticated 
                ? "Please log in as a student to ask questions"
                : "Ask about fees, attendance, grades, timetable, teachers..."
            }
            className={`chat-input ${!isAuthenticated ? 'disabled' : ''}`}
            disabled={isLoading || !isAuthenticated}
            aria-label="Type your question"
          />
          <button
            onClick={handleSend}
            disabled={!input.trim() || isLoading || !isAuthenticated}
            className="send-btn"
            aria-label="Send message"
          >
            {isLoading ? (
              <Loader2 size={18} className="spin" />
            ) : (
              <Send size={18} />
            )}
          </button>
        </div>
        <div className="input-hint">
          {isAuthenticated 
            ? "Press Enter to send • Ask natural questions like 'How much fee do I owe?' or 'What's my attendance?'"
            : "Log in to access the AI assistant"
          }
        </div>
      </div>
    </div>
  );
};

export default ERPChatBot;
